/**
 * App.jsx
 * ─────────────────────────────────────────────────────────────
 * Componente raíz. Envuelve la app con el proveedor de
 * autenticación para que cualquier componente pueda
 * acceder al contexto con useAuth().
 */

import { AuthProvider } from './context/AuthContext'
import AppRouter        from './router/AppRouter'

export default function App() {
  return (
    <AuthProvider>
      <AppRouter />
    </AuthProvider>
  )
}
